INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台姑娘态度还是不错的，送了入住鲜花。酒店地处广州旧cbd黄金地段，交通便利。酒', '前台姑娘态度还是不错的，送了入住鲜花。酒店地处广州旧cbd黄金地段，交通便利。酒店富丽堂皇，外国人云集，但因为设计年代久远，尽显年代气息，花园酒店，广州必定要打卡的地标建筑之一', '2023-11-06', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000ciym1es2324_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000ciyiyum354A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000ciyek35DAC9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次和家人来到广州游玩，入住了越秀区的广州花园酒店。团的是之前在携程订的套餐服务', '这次和家人来到广州游玩，入住了越秀区的广州花园酒店。团的是之前在携程订的套餐服务，有幸升级了套房。性价比上没得说，1600住了两晚。还有行政。李玉旋转餐厅的早餐。但是套房的缺点就是设施成就领域期的水忽冷忽热。正值楼下地铁施工，每天早上8点都会有。机器的声音伴随着闹钟声响虽然出门旅游不会睡懒觉，但是这个还是有一点美中不足。作为老牌酒店，他们的服务还是非常的不错，特别是在广交会期间。外国人虽然繁多，但是服务总体还是非常的热情，能够感受到五星级酒店的特殊。', '2023-10-22', 4, '[''性价比'', ''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000cfpq051A9A1_R_150_150_R5_Q70_D.webp\", \"https://dimg04.c-ctrip.com/images/0232212000cfppthe1BDB_R_150_150_R5_Q70_D.webp\", \"https://dimg04.c-ctrip.com/images/0232c12000cfpomvyB81C_R_150_150_R5_Q70_D.webp\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店就是住在花园里，亮点是花园瀑布下午茶，还有4楼博物馆也可免费参观，很不错的体', '酒店就是住在花园里，亮点是花园瀑布下午茶，还有4楼博物馆也可免费参观，很不错的体验哦', '2024-01-17', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235o12000cylf1nf3A67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000cylwem06FA9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000cyl2iyp8E71_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000cylw82h7600_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间温馨，床品很好，服务范到位。餐厅美食完美多样！可以停车后不能直达大厅，需要出', '房间温馨，床品很好，服务范到位。餐厅美食完美多样！可以停车后不能直达大厅，需要出地面步行一小段才可以。', '2024-01-10', 5, '[''房间设施'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000cwm3gjs0027_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000cwly5rr2CF0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000cwlqwzf0862_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000cwlgp2x01D7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '值得信赖携程推荐，短短的三天让我们体会到了广州花园酒店服务管理水平和世界名牌酒店', '值得信赖携程推荐，短短的三天让我们体会到了广州花园酒店服务管理水平和世界名牌酒店的接轨，选择花园酒店是我们的首选??????', '2023-12-18', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0205p12000cr5hlrgF3B1_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234h12000cr5d7iu3635_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店过年气氛很好，酒店环境不错，有瀑布花园，适合全家出游', '酒店过年气氛很好，酒店环境不错，有瀑布花园，适合全家出游', '2024-02-14', 4, '[''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236n12000d77r60j954F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂布置精美，后花园景色很美，房间卫生不错，工作人员服务热情。入住率高，早餐需排', '大堂布置精美，后花园景色很美，房间卫生不错，工作人员服务热情。入住率高，早餐需排队等候。
酒店旁边有施工，略吵
康体中心洗浴设施旧，热水供应不足', '2023-11-26', 4, '[''安静程度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236112000cn1vlfb304A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000cn20eyz52DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000cn22x7s6357_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州的老牌五星酒店，服务还是不错的，环境也很好，酒店干净卫生，就是我们入住的房间', '广州的老牌五星酒店，服务还是不错的，环境也很好，酒店干净卫生，就是我们入住的房间位置很偏感觉不是很舒服。', '2024-03-08', 4, '[''整体满意度'', ''卫生状况'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0232612000ddf56nn98D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000ddf5z0720AF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000ddf5atnAB50_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '感受下老酒店历久弥新～属实是不错的，整体的感觉，除了客房层高偏矮，老酒店也确实是', '感受下老酒店历久弥新～属实是不错的，整体的感觉，除了客房层高偏矮，老酒店也确实是如此，现在也足可见当年的辉煌', '2023-12-24', 5, '[''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236u12000csht5woB3B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000cshv53w96C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000cshrxrzD505_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000cshtfct038A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000cshxu073F68_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000cshy634D446_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000cshsv4346A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000cshxt3uC42C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000csi02ctDCAB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店地理位置非常好，环境优美，国庆节活动丰富多彩。酒店本身很有历史文化底蕴，建议', '酒店地理位置非常好，环境优美，国庆节活动丰富多彩。酒店本身很有历史文化底蕴，建议可以体验酒店介绍的26个打卡点，特别感谢小梁的细致周到讲解，下次还会选择这里。', '2024-10-02', 5, '[''整体满意度'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000fxdd08g042E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000fxe89vc52A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000fxauz2d8C46_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次选择了历史悠久的花园酒店 ', '这次选择了历史悠久的花园酒店 
1k+的2天1夜大床套餐真的很划算（含早+晚，叠叠高一份）check in的时候前台小姐姐还给宝宝送了冰箱贴 她好开心
??
本来我们套餐是花园大床 考虑到我们有宝宝 给我们升级到了红棉套房 比原来房间面积大了一倍 感谢酒店的贴心安排
房间里的缺点就是 老旧的味道有点点重 空调也是时不时会有很强的运转声音 其他都还阔以
枕头如果睡得不合适可以让服务员换的
??
选择这个酒店就是他们家好吃的特别多 荔湾亭和瀑布酒店我们都试了 真的不错 瀑布餐厅的自助晚餐我个人认为与其他酒店的自助晚餐都不太一样 菜式都比较有新意 味道也很不错 最近活动价388/位 推荐来试试 
荔湾亭的1蚊1碗豆腐花活动也是很惊艳 整体出品也在线 推荐
??
在花园酒店里面逛一天没有问题 还有博物馆可以参观（周一休馆）免费开放的
服务是不错的 工作人员都会耐心细致地回答我们提出的疑问', '2023-09-26', 4, '[''性价比'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232712000c8ygeki60A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000c8ycfubF6BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000c8y9vnw4FB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000c8yhwi8C41E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000c8yeofl7B81_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000c8y55gqA746_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000c8ybox7243C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000c8yfk6e17DF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000c8ya08v6A94_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店在老城区，外宾比较多。花园房型设施比较老旧，套房是新装修还可以。', '酒店在老城区，外宾比较多。花园房型设施比较老旧，套房是新装修还可以。', '2024-02-12', 4, '[''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000d6qc49e15DF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间忘记拍摄了，非常不错床很舒服睡了好觉', '房间忘记拍摄了，非常不错床很舒服睡了好觉', '2024-02-27', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234e12000daukljxAA4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000dauo4oiF4DE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '庆祝结婚纪念日，好多谢花园酒店为我们带来惊喜，不但布置了房间还送了一个漂亮的蛋糕', '庆祝结婚纪念日，好多谢花园酒店为我们带来惊喜，不但布置了房间还送了一个漂亮的蛋糕，免费升级了房型，服务和环境非常nice，下次还会继续选择，感谢这次为我们服务的各位靓女们，非常感谢！??????????', '2023-10-14', 5, '[''前台服务'', ''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232212000ce0aofb268F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231b12000ce0ao2w3E4F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000ce0aknq02FA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000ce0aomz1FCB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000ce0ao475DD7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000ce0aozkD858_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000ce0arpk0EFD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000ce0anqw5E98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000ce0at3l179C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园作为老五星，不管是服务上还是设施上都应该有它的名字。', '花园作为老五星，不管是服务上还是设施上都应该有它的名字。
先说这次的不足：
①广交会期间，办理入住窗口仅开放两个，导致入住等待将近一个小时期间。办理入住是迎宾的第二道线，如果长时间焦灼等待，让本来就旅途疲惫的人打破第一印象。
②外宾与外地宾客的接待，服务上会有一定差异，可以理解是因为会议期间作为接待酒店，对外宾有相应的服务。但，是不是忽略了一些游客的感受
③临街地铁施工，非常吵。周末无休早8晚10，在办理入住时无人提示，导致好不容易办好入住，又需要调换房间。如实在是没有其他房间调换的宾客，也未提前准备耳塞。

再说下好的地方：
①服务：从迎宾至早上的贴心服务，礼宾部做到应该做的标准五星酒店应有的程度
②环境交通：相对交通便利，如果为了吃饭购物相对方便。
③卫生：卫生还是依旧很干净，部分配置相对老旧，但扛得住用
希望作为老五星，去其糟粕取其精华，越来越好', '2023-10-15', 5, '[''退房/入住效率'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233g12000ce8w41r8BE4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '给免费升级了红棉大床房 房间确实很大 还有健身器材 早餐也很丰富 唯一不好的是楼', '给免费升级了红棉大床房 房间确实很大 还有健身器材 早餐也很丰富 唯一不好的是楼下市政建设在修地铁 好在晚上十点结束 早上八九点才开始施工 酒店本身服务是很好的 地理位置也很优越', '2023-11-02', 5, '[''整体满意度'', ''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000chwnssyCACF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000chwdccv5926_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000chwme6v6440_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000chwa6ooF554_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000chwjxv55BA2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很喜欢住在花园，酒店很有底蕴，但房间设施又比较新，不管是酒店的味道还是服务都很舒', '很喜欢住在花园，酒店很有底蕴，但房间设施又比较新，不管是酒店的味道还是服务都很舒服。入住有送鲜花，真的让人心情很好。
